INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('FINAL_1: Le customer acquisition cost (CAC) doit etre calcule en incluant: salaires marketing+vente, outils, ads, contenu, events. Pas juste les ads.', 'CAC complet: salaires + outils + ads + contenu + events. Pas juste ads', 'comptable', 'best_practice', 0.88, 'final_pack', 'system'),
('FINAL_2: Le SaaS rule of 40: taux de croissance annuel + marge EBITDA > 40% = entreprise en bonne sante. Les top SaaS sont > 60%.', 'Rule of 40: croissance + marge > 40%. Top > 60%', 'comptable', 'insight', 0.85, 'final_pack', 'system'),
('FINAL_3: Le net revenue retention (NRR) est la metrique la plus importante pour les investisseurs SaaS. > 120% = les clients existants generent plus chaque annee.', 'NRR > 120%: clients existants generent plus chaque annee. #1 metrique investisseurs', 'comptable', 'insight', 0.88, 'final_pack', 'system'),
('FINAL_4: Le content-market fit test: publier 10 contenus differents (formats, sujets, angles). Les 2-3 qui performent 3x mieux = votre content-market fit.', 'Content-market fit: 10 contenus → 2-3 performent 3x = votre fit', 'content', 'best_practice', 0.85, 'final_pack', 'system'),
('FINAL_5: Le viral loop engineering: chaque utilisateur doit naturellement amener d autres utilisateurs. Le K-factor (invitations × conversion) > 1 = croissance virale.', 'Viral loop: K = invitations × conversion. > 1 = croissance virale', 'marketing', 'insight', 0.85, 'final_pack', 'system'),
('FINAL_6: Le competitive displacement strategy: identifier LA faiblesse #1 du concurrent et en faire SA force #1. Positionner comme l anti-concurrent.', 'Competitive displacement: faiblesse #1 concurrent = force #1 soi', 'ceo', 'best_practice', 0.85, 'final_pack', 'system'),
('FINAL_7: Le sales velocity formula: (# opportunities × avg deal value × win rate) / avg sales cycle length. Optimiser CHAQUE variable.', 'Sales velocity: opportunities × value × win% / cycle. Optimiser chaque variable', 'commercial', 'best_practice', 0.85, 'final_pack', 'system'),
('FINAL_8: Le email segmentation avancee: par lifecycle (prospect/trial/client), par engagement (actif/inactif), par persona (restaurateur/coach), par score (froid/chaud).', 'Segmentation email: lifecycle × engagement × persona × score', 'email', 'best_practice', 0.88, 'final_pack', 'system'),
('FINAL_9: Le SEO topical authority building: couvrir 30+ articles sur 1 sujet = Google considere le site comme autorite sur ce sujet. Ranker sur tous les mots-cles lies.', 'Topical authority: 30+ articles 1 sujet = autorite Google sur ce sujet', 'seo', 'best_practice', 0.88, 'final_pack', 'system'),
('FINAL_10: Le ad creative psychology: les premieres 2 secondes determinent 90% du succes. Hook visuel (mouvement/couleur) + hook textuel (chiffre/question) = arret du scroll.', 'Creative psychology: 2 premieres secondes = 90% succes. Hook visuel + textuel', 'ads', 'best_practice', 0.88, 'final_pack', 'system'),
('FINAL_11: Le DM Instagram value-first: les 3 premiers DMs doivent apporter de la valeur (compliment, conseil, resource) SANS rien demander. Le 4e DM peut proposer un RDV.', 'DM value-first: 3 DMs valeur sans demander → 4e DM = proposer RDV', 'dm_instagram', 'best_practice', 0.88, 'final_pack', 'system'),
('FINAL_12: Le WhatsApp engagement rules: repondre dans les 5 min aux messages entrants. Jamais de message non sollicite. Toujours proposer l opt-out.', 'WhatsApp rules: repondre 5 min + jamais non sollicite + opt-out', 'whatsapp', 'best_practice', 0.90, 'final_pack', 'system'),
('FINAL_13: Le chatbot qualification flow: 3 questions pour qualifier (secteur? besoin? budget?) → si qualifie → proposer RDV commercial. Si pas qualifie → rediriger vers FAQ.', 'Chatbot qualification: 3 questions → qualifie=RDV, non=FAQ', 'chatbot', 'best_practice', 0.85, 'final_pack', 'system'),
('FINAL_14: Le Google My Business post types: offre (promo), evenement (date), mise a jour (news), produit (catalogue). Alterner les 4 types chaque semaine.', 'GMB posts: offre + evenement + update + produit. Alterner 4 types/semaine', 'gmaps', 'best_practice', 0.85, 'final_pack', 'system'),
('FINAL_15: Le TikTok content pillars: 3-5 themes recurrents (astuces, behind-the-scenes, reactions, tutoriels, storytelling). Tourner entre les piliers.', 'TikTok pillars: 3-5 themes. Astuces + BTS + reactions + tutos + storytelling', 'tiktok_comments', 'best_practice', 0.82, 'final_pack', 'system'),
('FINAL_16: Le CEO decision matrix: pour chaque decision, evaluer Impact (1-5) × Urgence (1-5) × Faisabilite (1-5). Score > 60 = action immediate.', 'CEO decision: Impact × Urgence × Faisabilite. > 60 = action immediate', 'ceo', 'best_practice', 0.85, 'final_pack', 'system'),
('FINAL_17: Le retention first 90 days: les 90 premiers jours determinent 80% de la retention long terme. Investir massivement dans l onboarding et le time-to-value.', 'Retention: 90 premiers jours = 80% retention long terme. Investir onboarding+TTV', 'retention', 'insight', 0.90, 'final_pack', 'system'),
('FINAL_18: Le onboarding gamification: progress bar visible + congratulations a chaque etape + badge de completion = +40% completion + +25% retention J30.', 'Onboarding gamification: progress + congrats + badge = +40% completion +25% retention', 'onboarding', 'best_practice', 0.85, 'final_pack', 'system'),
('FINAL_19: Le RH remote team rituals: daily standup 15min + weekly all-hands 30min + monthly retrospective 1h + quarterly offsite 2j = equipe alignee.', 'Remote rituals: daily 15min + weekly 30min + monthly 1h + quarterly 2j', 'rh', 'best_practice', 0.82, 'final_pack', 'system'),
('FINAL_20: Le marketing funnel metrics: TOFU (impressions, reach, traffic), MOFU (leads, MQL, engagement), BOFU (SQL, opportunities, deals), POST (NPS, referrals, expansion).', 'Funnel metrics: TOFU reach, MOFU leads, BOFU deals, POST NPS+referrals', 'marketing', 'best_practice', 0.85, 'final_pack', 'system'),
('FINAL_21: Le cross-agent intelligence protocol: chaque agent partage ses 3 top insights quotidiens dans le shared context. Le CEO les redistribue aux agents concernes.', 'Cross-agent: 3 insights/jour/agent → CEO redistribue aux agents concernes', NULL, 'best_practice', 0.88, 'final_pack', 'system'),
('FINAL_22: Le customer lifetime journey phases: Awareness → Consideration → Purchase → Onboarding → Adoption → Expansion → Advocacy. Contenu adapte a chaque phase.', 'Customer journey 7 phases: awareness → consideration → purchase → onboarding → adoption → expansion → advocacy', NULL, 'best_practice', 0.85, 'final_pack', 'system'),
('FINAL_23: Le pricing page conversion optimization: 3-4 plans max + highlight recommande + toggle mensuel/annuel + FAQ en bas + trust badges + social proof.', 'Pricing page: 3-4 plans + highlight + toggle + FAQ + trust + proof', 'commercial', 'best_practice', 0.88, 'final_pack', 'system'),
('FINAL_24: Le email subject line formulas gagnantes: [Prenom]+question, [Chiffre]+benefice, [Erreur]+a eviter, [Nouveau]+annonce, [Exclusif]+offre.', 'Subject formulas: prenom+question, chiffre+benefice, erreur, nouveau, exclusif', 'email', 'best_practice', 0.85, 'final_pack', 'system'),
('FINAL_25: Le SEO audit trimestriel checklist: indexation, vitesse, mobile, structured data, internal links, content gaps, backlinks, cannibalisation, 404s.', 'SEO audit trimestriel: 9 points (indexation, vitesse, mobile, schema, liens, gaps, backlinks, cannibal, 404)', 'seo', 'best_practice', 0.85, 'final_pack', 'system'),
('FINAL_26: Le ad testing protocol: lancer 5 creatives → 500 impressions chacune → garder les 2 avec CTR > 2% → scale → remplacer les 3 perdantes → repeter.', 'Ad testing: 5 creatives × 500 imp → garder CTR>2% → scale → remplacer → repeter', 'ads', 'best_practice', 0.85, 'final_pack', 'system'),
('FINAL_27: Le community building formula: contenu de valeur (attirer) + interaction (engager) + reconnaissance (valoriser) + exclusivite (retenir) = communaute forte.', 'Community: contenu attirer + interaction engager + reconnaissance + exclusivite retenir', 'marketing', 'best_practice', 0.82, 'final_pack', 'system'),
('FINAL_28: Le product-led growth metrics: signup rate, activation rate, feature adoption, expansion rate, referral rate, NPS. Les 6 metriques PLG essentielles.', 'PLG metrics: signup, activation, adoption, expansion, referral, NPS', 'ceo', 'best_practice', 0.85, 'final_pack', 'system'),
('FINAL_29: Le data-driven content strategy: analyser les top 20 articles par trafic, les top 20 par conversion, et les top 20 par backlinks. Creer plus de contenu similaire.', 'Content data-driven: top 20 trafic + conversion + backlinks → creer similaire', 'content', 'best_practice', 0.85, 'final_pack', 'system'),
('FINAL_30: Le pipeline forecast accuracy: mesurer chaque mois le forecast vs le reel. Si l ecart > 20% → revoir les criteres de qualification des deals.', 'Forecast accuracy: ecart > 20% → revoir criteres qualification', 'commercial', 'best_practice', 0.82, 'final_pack', 'system'),
('FINAL_31: Le email campaign dashboard: OR, CTR, reply rate, unsub rate, bounce rate, revenue generated, cost per acquisition. Par campagne ET par segment.', 'Email dashboard: OR+CTR+reply+unsub+bounce+revenue+CPA. Par campagne + segment', 'email', 'best_practice', 0.85, 'final_pack', 'system'),
('FINAL_32: Le link building outreach: identifier 50 sites DR>40 dans la niche → proposer un contenu de valeur (guest post, etude, infographie) → obtenir 5-10 backlinks/mois.', 'Link building: 50 sites DR>40 → contenu valeur → 5-10 backlinks/mois', 'seo', 'best_practice', 0.82, 'final_pack', 'system'),
('FINAL_33: Le creative refresh cycle: semaine 1 = concevoir 5 creatives, semaine 2 = lancer + tester, semaine 3 = analyser + iterer, semaine 4 = scale gagnantes + concevoir 5 nouvelles.', 'Creative refresh 4 semaines: S1 concevoir, S2 tester, S3 analyser, S4 scale + nouvelles', 'ads', 'best_practice', 0.82, 'final_pack', 'system'),
('FINAL_34: Le DM conversion optimization: personnaliser chaque DM avec 1 element specifique au prospect (dernier post, bio, story recente). Jamais de template generique.', 'DM personnalise: 1 element specifique prospect (post, bio, story). 0 generique', 'dm_instagram', 'best_practice', 0.88, 'final_pack', 'system'),
('FINAL_35: Le WhatsApp business automation: message de bienvenue auto + confirmation RDV auto + rappel 24h auto + suivi post-achat auto + demande avis auto.', 'WhatsApp auto: bienvenue + confirm RDV + rappel + suivi + demande avis', 'whatsapp', 'best_practice', 0.85, 'final_pack', 'system'),
('FINAL_36: Le chatbot continuous improvement: analyser les conversations echouees chaque semaine → ajouter les reponses manquantes → le taux de resolution augmente de 5%/mois.', 'Chatbot improvement hebdo: conversations echouees → ajouter reponses = +5%/mois resolution', 'chatbot', 'best_practice', 0.85, 'final_pack', 'system'),
('FINAL_37: Le GMaps review strategy: demander un avis a chaque client satisfait (QR code, SMS, email). Objectif: 10+ nouveaux avis/mois. Repondre a 100% des avis < 24h.', 'GMaps: demander avis chaque client. 10+ avis/mois. Repondre 100% < 24h', 'gmaps', 'best_practice', 0.88, 'final_pack', 'system'),
('FINAL_38: Le TikTok analytics mastery: watch time, completion rate, shares, comments, follows from video, profile visits. Les 6 metriques a tracker.', 'TikTok analytics: watch time + completion + shares + comments + follows + profile visits', 'tiktok_comments', 'best_practice', 0.82, 'final_pack', 'system'),
('FINAL_39: Le CEO agent intelligence cascade: trend detectee → evaluer impact → decider action → deleguer a l agent concerne → suivre execution → mesurer resultat → apprendre.', 'CEO cascade: trend → impact → action → deleguer → suivre → mesurer → apprendre', 'ceo', 'best_practice', 0.90, 'final_pack', 'system'),
('FINAL_40: Le retention engagement ladder: login → use core feature → use 2nd feature → invite colleague → upgrade → become advocate. Chaque etape = plus de retention.', 'Retention ladder: login → core → 2nd feature → invite → upgrade → advocate', 'retention', 'best_practice', 0.85, 'final_pack', 'system'),
('FINAL_41: Le onboarding success metrics: signup-to-activation rate, time-to-first-value, onboarding completion rate, day-7 retention, day-30 retention.', 'Onboarding metrics: activation rate + TTV + completion + D7 retention + D30 retention', 'onboarding', 'best_practice', 0.88, 'final_pack', 'system'),
('FINAL_42: Le comptable monthly financial review: MRR vs target, burn rate vs budget, CAC vs LTV, pipeline vs forecast, runway update. 5 points chaque mois.', 'Monthly financial: MRR + burn + CAC/LTV + pipeline + runway. 5 points', 'comptable', 'best_practice', 0.85, 'final_pack', 'system'),
('FINAL_43: Le RH performance framework: objectifs mesurables (70%) + competences comportementales (20%) + contribution culture (10%). Evaluation trimestrielle.', 'Performance: objectifs 70% + competences 20% + culture 10%. Trimestriel', 'rh', 'best_practice', 0.82, 'final_pack', 'system'),
('FINAL_44: Le marketing channel efficiency: mesurer le CAC par canal (SEO, ads, referral, content, events). Le canal avec le CAC le plus bas = investir plus.', 'Channel efficiency: CAC par canal. Plus bas CAC = investir plus', 'marketing', 'best_practice', 0.85, 'final_pack', 'system'),
('FINAL_45: Le cross-agent data synchronization: les donnees CRM, les metriques email, les stats social, les KPIs ads doivent etre accessibles a TOUS les agents en temps reel.', 'Data sync cross-agent: CRM+email+social+ads accessibles tous agents temps reel', NULL, 'best_practice', 0.88, 'final_pack', 'system'),
('FINAL_46: Le customer success playbook: trial → onboarding → adoption → expansion → renewal → advocacy. Chaque etape a ses actions, metriques et triggers.', 'CS playbook: trial → onboarding → adoption → expansion → renewal → advocacy', 'retention', 'best_practice', 0.85, 'final_pack', 'system'),
('FINAL_47: Le KeiroAI intelligence loop: agents executent → resultats analyses → learnings RAG → agents ameliores → meilleurs resultats → plus de learnings. Cercle vertueux.', 'KeiroAI loop: executer → analyser → apprendre → ameliorer → meilleurs resultats', NULL, 'best_practice', 0.92, 'final_pack', 'system'),
('FINAL_48: Le KeiroAI moat technologique: 17 agents coordonnes + CEO IA + RAG enrichi par chaque client + auto-improvement + intelligence partagee = aucun concurrent ne peut copier.', 'KeiroAI moat: 17 agents + CEO + RAG + auto-improve + intelligence = incopiable', 'ceo', 'best_practice', 0.95, 'final_pack', 'system'),
('FINAL_49: Le KeiroAI north star metric: nombre d actions agents reussies par client par semaine. Si ce nombre augmente → satisfaction augmente → retention augmente → revenus augmentent.', 'North star: actions reussies/client/semaine. Augmente → satisfaction → retention → revenus', 'ceo', 'best_practice', 0.92, 'final_pack', 'system'),
('FINAL_50: Le KeiroAI mission: democratiser l acces a une equipe marketing d elite pour chaque entrepreneur. 17 agents IA, 24/7, a partir de 49€/mois. L avenir du marketing.', 'KeiroAI mission: equipe marketing elite 17 agents 24/7 pour chaque entrepreneur 49€/mois', 'ceo', 'best_practice', 0.95, 'final_pack', 'system')
